sql:
SELECT series_name 
FROM series 
WHERE release_year > 2003 AND average_rating > 7.0;

SELECT episode_id, date_recorded, viewer_count, rating, demographic_info
FROM viewer_stats
WHERE viewer_count = (SELECT MAX(viewer_count) FROM viewer_stats);

SELECT e.episode_id, e.title, d.director_name
FROM episodes e
JOIN directors d ON e.director_id = d.director_id
WHERE e.us_viewers_millions = (
    SELECT MAX(us_viewers_millions) FROM episodes
);

SELECT title
FROM episodes
WHERE runtime = (SELECT MAX(runtime) FROM episodes);
